def summarize_old_history(messages):
    """Condense old conversation into a summary."""
    if len(messages) < 20:
        return None  # Don't summarize if short

    # Extract old turns (everything except last 10)
    old_turns = messages[:-10]

    # Ask Claude to summarize
    summary_response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[
            {"role": "user", "content": f"Summarize this conversation in 3 bullet points:\n\n{old_turns}"}
        ]
    )

    return summary_response.content[0].text

messages = []

# Turn 1-20: Normal conversation
for i in range(20):
    messages.append({"role": "user", "content": f"Question {i}"})
    response = client.messages.create(model="claude-sonnet-4-6", max_tokens=1024, messages=messages)
    messages.append({"role": "assistant", "content": response.content})

# Turn 21: Summarize old history
summary = summarize_old_history(messages)
if summary:
